import{_ as a,o as t,c as o,ae as e}from"./chunks/framework.Dzr56EFm.js";const A=JSON.parse('{"title":"大厂战略 - 2026-05-06","description":"","frontmatter":{"date":"2026-05-06T00:00:00.000Z","category":"BigTech"},"headers":[],"relativePath":"daily/2026-05-06-bigtech.md","filePath":"daily/2026-05-06-bigtech.md"}'),n={name:"daily/2026-05-06-bigtech.md"};function s(i,r,p,g,h,l){return t(),o("div",null,[...r[0]||(r[0]=[e('<h1 id="大厂战略-2026-05-06" tabindex="-1">大厂战略 - 2026-05-06 <a class="header-anchor" href="#大厂战略-2026-05-06" aria-label="Permalink to &quot;大厂战略 - 2026-05-06&quot;">​</a></h1><blockquote><p>OpenAI、Google、Apple、Microsoft、Meta、Amazon战略</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日大厂战略领域主要动态集中在人工智能的应用和发展。微软AI通过先进工具提升销售策略，同时提供AI战略规划框架助力企业实现业务价值。亚马逊则通过Nova AI挑战赛寻求开发下一代广告AI应用，并利用AI代理预测和应对网络威胁。最值得关注的是微软的AI战略规划框架和亚马逊的AI挑战赛，它们分别代表了AI在商业战略和技术创新中的应用。</p><hr><h3 id="_1-商业和企业战略中的人工智能-微软ai" tabindex="-1">1. 商业和企业战略中的人工智能 | 微软AI <a class="header-anchor" href="#_1-商业和企业战略中的人工智能-微软ai" aria-label="Permalink to &quot;1. 商业和企业战略中的人工智能 | 微软AI&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/ai/ai-business-value-and-benefits" target="_blank" rel="noreferrer">AI in Business and Corporate Strategy | Microsoft AI</a></p><p><strong>一句话摘要</strong>: 微软AI通过先进工具显著提升销售策略和成果。</p><p><strong>能解决什么问题</strong>: 解决企业销售过程中的自动化、个性化和实时数据分析问题。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过自动化和数据分析提升业务效率。</p><p><strong>示例场景</strong>: 使用PowerPoint Copilot自动创建演示文稿和数据可视化。</p><hr><h3 id="_2-构建你的ai战略-云采用框架-微软学习" tabindex="-1">2. 构建你的AI战略 - 云采用框架 - 微软学习 <a class="header-anchor" href="#_2-构建你的ai战略-云采用框架-微软学习" aria-label="Permalink to &quot;2. 构建你的AI战略 - 云采用框架 - 微软学习&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://learn.microsoft.com/en-us/azure/cloud-adoption-framework/ai/strategy" target="_blank" rel="noreferrer">Create your AI strategy - Cloud Adoption Framework - Microsoft Learn</a></p><p><strong>一句话摘要</strong>: 微软提供AI战略规划框架，助力企业实现业务价值。</p><p><strong>能解决什么问题</strong>: 帮助企业识别AI应用案例，选择技术，建立数据治理，实施负责任的AI。</p><p><strong>产品应用</strong>: 适用于各规模组织，通过微软AI技术实现业务数据预测和产品管理。</p><p><strong>示例场景</strong>: 虚构公司Contoso使用AI预测销售数据和库存管理。</p><hr><h3 id="_3-亚马逊nova-ai挑战赛-可信人工智能" tabindex="-1">3. 亚马逊Nova AI挑战赛：可信人工智能 <a class="header-anchor" href="#_3-亚马逊nova-ai挑战赛-可信人工智能" aria-label="Permalink to &quot;3. 亚马逊Nova AI挑战赛：可信人工智能&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/nova-ai-challenge" target="_blank" rel="noreferrer">Amazon Nova AI Challenge: Trusted AI</a></p><p><strong>一句话摘要</strong>: 亚马逊寻求应用科学家开发下一代广告商AI应用。</p><p><strong>能解决什么问题</strong>: 提高全球广告商体验，实现复杂工作流程中的自主决策。</p><p><strong>产品应用</strong>: 应用于广告和制造领域，提升效率和可靠性。</p><p><strong>示例场景</strong>: 优化全球广告投放策略，提高制造流程决策速度。</p><hr><h3 id="_4-亚马逊宣布2026年亚马逊新星ai挑战赛-可信软件代理赛道" tabindex="-1">4. 亚马逊宣布2026年亚马逊新星AI挑战赛：可信软件代理赛道 <a class="header-anchor" href="#_4-亚马逊宣布2026年亚马逊新星ai挑战赛-可信软件代理赛道" aria-label="Permalink to &quot;4. 亚马逊宣布2026年亚马逊新星AI挑战赛：可信软件代理赛道&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/nova-ai-challenge/amazon-announces-the-2026-amazon-nova-ai-challenge-trusted-software-agents" target="_blank" rel="noreferrer">Amazon announces the 2026 Amazon Nova AI Challenge: Trusted Software Agents track - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊寻求应用科学家开发下一代广告代理AI应用。</p><p><strong>能解决什么问题</strong>: 提升亚马逊广告商在全球范围内的广告体验。</p><p><strong>产品应用</strong>: 应用于广告流程优化，提高广告效率和客户满意度。</p><p><strong>示例场景</strong>: 全球广告商使用AI系统优化广告投放策略。</p><hr><h3 id="_5-亚马逊如何利用ai代理预测和应对网络威胁" tabindex="-1">5. 亚马逊如何利用AI代理预测和应对网络威胁 <a class="header-anchor" href="#_5-亚马逊如何利用ai代理预测和应对网络威胁" aria-label="Permalink to &quot;5. 亚马逊如何利用AI代理预测和应对网络威胁&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/blog/how-amazon-uses-ai-agents-to-anticipate-and-counter-cyber-threats" target="_blank" rel="noreferrer">How Amazon uses AI agents to anticipate and counter cyber threats - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊开发AI和机器学习系统以预测和对抗网络威胁。</p><p><strong>能解决什么问题</strong>: 解决网络威胁的预测和实时响应问题。</p><p><strong>产品应用</strong>: 可应用于广告、制造等领域，提升安全性和效率。</p><p><strong>示例场景</strong>: 在广告领域，通过AI优化广告投放效果。</p><hr><h3 id="_6-研究合作-亚马逊科学" tabindex="-1">6. 研究合作 - 亚马逊科学 <a class="header-anchor" href="#_6-研究合作-亚马逊科学" aria-label="Permalink to &quot;6. 研究合作 - 亚马逊科学&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/academic-engagements/research-collaborations" target="_blank" rel="noreferrer">Research collaborations - Amazon Science</a></p><p><strong>一句话摘要</strong>: 寻找应用科学家开发下一代亚马逊广告商AI应用</p><p><strong>能解决什么问题</strong>: 提升亚马逊广告商在全球范围内的体验</p><p><strong>产品应用</strong>: 应用于广告商工作流程，实现自主推理、规划和行动</p><p><strong>示例场景</strong>: 全球广告投放的自动化优化和决策</p><hr><h3 id="_7-人工智能-ai-亚马逊科学" tabindex="-1">7. 人工智能（AI）- 亚马逊科学 <a class="header-anchor" href="#_7-人工智能-ai-亚马逊科学" aria-label="Permalink to &quot;7. 人工智能（AI）- 亚马逊科学&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.amazon.science/tag/artificial-intelligence" target="_blank" rel="noreferrer">Artificial intelligence (AI) - Amazon Science</a></p><p><strong>一句话摘要</strong>: 亚马逊利用AI技术提升全球在线购物体验</p><p><strong>能解决什么问题</strong>: 解决产品身份和关系识别的AI挑战</p><p><strong>产品应用</strong>: 应用于亚马逊目录系统，优化搜索和浏览体验</p><p><strong>示例场景</strong>: 通过VLMs识别产品独特性及其相互关系</p><hr><h3 id="_8-微软2025年未来工作报告-负责任的人工智能组织成熟度模型" tabindex="-1">8. 微软2025年未来工作报告：负责任的人工智能组织成熟度模型 <a class="header-anchor" href="#_8-微软2025年未来工作报告-负责任的人工智能组织成熟度模型" aria-label="Permalink to &quot;8. 微软2025年未来工作报告：负责任的人工智能组织成熟度模型&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/research/wp-content/uploads/2025/12/New-Future-Of-Work-Report-2025.pdf" target="_blank" rel="noreferrer">[PDF] Microsoft New Future of Work Report 2025</a></p><p><strong>一句话摘要</strong>: 微软报告提出负责任AI组织成熟度模型，指导组织变革。</p><p><strong>能解决什么问题</strong>: 组织在采纳和构建AI能力时面临转型挑战。</p><p><strong>产品应用</strong>: 适用于企业规划负责任AI战略和实践，促进AI技术负责任地应用。</p><p><strong>示例场景</strong>: 企业通过RAI-OMM模型规划AI战略，确保AI应用符合伦理标准。</p><hr><h3 id="_9-ai作为平台转变-而非另一项实验" tabindex="-1">9. AI作为平台转变，而非另一项实验 <a class="header-anchor" href="#_9-ai作为平台转变-而非另一项实验" aria-label="Permalink to &quot;9. AI作为平台转变，而非另一项实验&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/industry/microsoft-in-business/thought-leadership/2026/04/21/ai-as-a-platform-shift-not-another-experiment/" target="_blank" rel="noreferrer">AI as a platform shift, not another experiment - Microsoft in Business Blogs</a></p><p><strong>一句话摘要</strong>: EY将AI融入全球战略，重塑税务、审计、咨询等服务。</p><p><strong>能解决什么问题</strong>: 如何将AI战略转化为大规模实际执行并保持信任。</p><p><strong>产品应用</strong>: 可应用于专业服务公司，通过AI提升数据处理、文档审查的速度和质量。</p><p><strong>示例场景</strong>: EY利用AI加速财务数据集分析和文档审查。</p><hr><h3 id="_10-meta与broadcom合作开发定制ai芯片" tabindex="-1">10. Meta与Broadcom合作开发定制AI芯片 <a class="header-anchor" href="#_10-meta与broadcom合作开发定制ai芯片" aria-label="Permalink to &quot;10. Meta与Broadcom合作开发定制AI芯片&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://about.fb.com/news/2026/04/meta-partners-with-broadcom-to-co-develop-custom-ai-silicon/" target="_blank" rel="noreferrer">Meta Partners With Broadcom to Co-Develop Custom AI Silicon</a></p><p><strong>一句话摘要</strong>: Meta和Broadcom达成超过1GW的合作协议，共同设计和扩展AI硬件。</p><p><strong>能解决什么问题</strong>: 解决全球数十亿人个人超级智能硬件需求问题。</p><p><strong>产品应用</strong>: 应用于Meta的AI基础设施，提升性能和效率。</p><p><strong>示例场景</strong>: 为全球用户提供个性化AI服务。</p><hr>',75)])])}const d=a(n,[["render",s]]);export{A as __pageData,d as default};
